// ── DOMAIN COLORS (matching academia) ─────────────────────────────────────
const SP_DOMAIN_COLORS = {
  kalam:'#c97a4c', fiqh:'#4c8bc9', falsafa:'#9a4cc9', tafsir:'#4cc97a',
  hadith:'#c9c44c', irfan:'#c94c7a', akhlaq:'#4cc9c9', tarikh:'#a07050'
};
const SP_DOMAIN_NAMES = {
  kalam:'Kalām', fiqh:'Fiqh & Uṣūl', falsafa:'Falsafa & Ḥikma', tafsir:'Tafsīr',
  hadith:'Ḥadīth', irfan:'ʿIrfān', akhlaq:'Akhlāq', tarikh:'Tārīkh'
};

// ── POPUP HTML INJECTION ───────────────────────────────────────────────────
function _spInit() {
  if (document.getElementById('sp-overlay')) return;

  const style = document.createElement('style');
  style.textContent = `
#sp-overlay {
  position: fixed; inset: 0; z-index: 900;
  background: rgba(8,6,4,0.6);
  display: none; align-items: center; justify-content: center;
  padding: 20px;
  backdrop-filter: blur(4px);
}
#sp-overlay.open { display: flex; }
#sp-panel {
  background: #13100a;
  border: 1px solid rgba(201,168,76,0.25);
  border-radius: 4px;
  max-width: 580px; width: 100%;
  max-height: 85vh;
  overflow-y: auto;
  position: relative;
  box-shadow: 0 20px 60px rgba(0,0,0,0.8);
  font-family: 'Crimson Pro', Georgia, serif;
  animation: spSlideIn 0.22s ease;
}
@keyframes spSlideIn { from{opacity:0;transform:translateY(12px)} to{opacity:1;transform:translateY(0)} }
#sp-close {
  position: absolute; top: 14px; right: 16px;
  background: none; border: none; cursor: pointer;
  color: rgba(245,239,224,0.4); font-size: 20px; line-height: 1;
  transition: color 0.2s; z-index: 2;
}
#sp-close:hover { color: rgba(245,239,224,0.85); }
#sp-body { padding: 28px 32px 24px; }
.sp-name {
  font-family: 'Playfair Display', serif;
  font-size: 22px; font-weight: 600;
  color: rgba(245,239,224,0.95);
  margin-bottom: 4px; padding-right: 32px;
}
.sp-arabic {
  font-family: 'Noto Naskh Arabic', serif;
  font-size: 15px; color: #7a6030;
  margin-bottom: 10px; direction: rtl;
}
.sp-meta {
  font-size: 13px; color: rgba(245,239,224,0.35);
  letter-spacing: 0.08em; margin-bottom: 14px;
}
.sp-domains { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 18px; }
.sp-domain-badge {
  font-size: 11px; letter-spacing: 0.1em; text-transform: uppercase;
  padding: 3px 10px; border-radius: 2px; border: 1px solid;
}
.sp-divider { height: 1px; background: rgba(201,168,76,0.1); margin-bottom: 16px; }
.sp-desc {
  font-size: 15.5px; line-height: 1.72;
  color: rgba(245,239,224,0.7);
  margin-bottom: 20px;
}
.sp-works-heading {
  font-size: 10.5px; letter-spacing: 0.25em; text-transform: uppercase;
  color: #7a6030; margin-bottom: 10px;
}
.sp-work {
  padding: 10px 14px; margin-bottom: 6px;
  background: rgba(255,255,255,0.02);
  border-left: 2px solid rgba(201,168,76,0.25);
}
.sp-work-title {
  font-family: 'Playfair Display', serif;
  font-size: 14px; font-weight: 600;
  color: rgba(245,239,224,0.85);
  margin-bottom: 4px;
}
.sp-work-desc {
  font-size: 14.5px; color: rgba(245,239,224,0.48); line-height: 1.6;
}
.sp-footer {
  padding: 14px 32px 20px;
  border-top: 1px solid rgba(201,168,76,0.08);
  display: flex; justify-content: space-between; align-items: center;
}
.sp-fulllink {
  font-family: 'Crimson Pro', Georgia, serif;
  font-size: 13px; letter-spacing: 0.12em; text-transform: uppercase;
  color: #7a6030; text-decoration: none;
  border-bottom: 1px solid rgba(201,168,76,0.2);
  transition: color 0.2s, border-color 0.2s;
}
.sp-fulllink:hover { color: #e8c97a; border-bottom-color: #c9a84c; }
.sp-note { font-size: 12px; color: rgba(245,239,224,0.2); }
`;
  document.head.appendChild(style);

  const overlay = document.createElement('div');
  overlay.id = 'sp-overlay';
  overlay.innerHTML = `<div id="sp-panel" role="dialog" aria-modal="true" aria-label="Scholar biography">
    <button id="sp-close" onclick="closeScholarPopup()" aria-label="Close">×</button>
    <div id="sp-body"></div>
    <div class="sp-footer">
      <a id="sp-fulllink" class="sp-fulllink" href="#">Full profile on Academic Map →</a>
    </div>
  </div>`;
  overlay.addEventListener('click', e => { if (e.target === overlay) closeScholarPopup(); });
  document.body.appendChild(overlay);

  // Escape key
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape') closeScholarPopup();
  });
}

// ── PUBLIC API ─────────────────────────────────────────────────────────────
function showScholarPopup(scholarId) {
  _spInit();
  const s = SCHOLAR_BIOS[scholarId];
  if (!s) return;
  const primaryColor = SP_DOMAIN_COLORS[s.domains[0]] || '#c9a84c';
  const badges = s.domains.map(d =>
    `<span class="sp-domain-badge" style="color:${SP_DOMAIN_COLORS[d]||'#c9a84c'};border-color:${SP_DOMAIN_COLORS[d]||'#c9a84c'}44;background:${SP_DOMAIN_COLORS[d]||'#c9a84c'}18">${SP_DOMAIN_NAMES[d]||d}</span>`
  ).join('');
  const works = s.works.map(w => `
    <div class="sp-work" style="border-left-color:${primaryColor}">
      <div class="sp-work-title">${w.title}</div>
      <div class="sp-work-desc">${w.desc}</div>
    </div>`).join('');

  const minorWksHtml = s.minorWorks && s.minorWorks.length ? '<div class="sp-works-heading" style="margin-top:14px;font-size:9.5px;">Minor & Related Works</div>' + s.minorWorks.map(w => {const dc=SP_DOMAIN_COLORS[w.domain]||'#c9a84c';return '<div style="display:flex;align-items:baseline;gap:7px;padding:4px 8px;margin-bottom:3px;border-left:2px solid '+dc+'33"><span style="width:5px;height:5px;border-radius:50%;background:'+dc+';flex-shrink:0;margin-top:5px;display:inline-block"></span><span style="flex:1;font-size:12.5px;color:rgba(245,239,224,0.42)">'+w.title+' — '+w.desc+'</span></div>';}).join('') : '';
  document.getElementById('sp-body').innerHTML = `
    <div class="sp-name">${s.name}</div>
    ${s.arabic ? `<div class="sp-arabic">${s.arabic}</div>` : ''}
    <div class="sp-meta">${s.dates} · ${s.era}${s.location ? ' · ' + s.location : ''}</div>
    <div class="sp-domains">${badges}</div>
    <div class="sp-divider"></div>
    <div class="sp-desc">${s.desc}</div>
    ${works ? `<div class="sp-works-heading">Major Works</div>${works}` : ''}
    ${minorWksHtml}`;

  // Determine full profile behaviour
  const onAcademia = window.location.pathname.includes('shia-academia');
  const fullLink = document.getElementById('sp-fulllink');
  if (onAcademia) {
    // On academia itself: switch to By Scholar tab and open modal directly
    fullLink.href = '#';
    fullLink.onclick = (e) => {
      e.preventDefault();
      closeScholarPopup();
      // Find and activate the By Scholar button
      const scholarBtn = [...document.querySelectorAll('.view-btn')]
        .find(b => b.textContent.trim() === 'By Scholar');
      if (scholarBtn) setView('scholar', scholarBtn);
      // Wait for cards to build, then open the modal
      setTimeout(() => {
        if (typeof openModal === 'function') openModal(scholarId);
      }, 60);
    };
  } else {
    fullLink.href = `shia-academia.html#scholar-${scholarId}`;
    fullLink.onclick = null;
  }

  document.getElementById('sp-overlay').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeScholarPopup() {
  const overlay = document.getElementById('sp-overlay');
  if (overlay) overlay.classList.remove('open');
  document.body.style.overflow = '';
}

// ── AUTO-INTERCEPT CROSS-LINKS ─────────────────────────────────────────────
// Intercept any anchor with href containing "scholar-" and show popup instead
document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('a[href*="scholar-"]').forEach(a => {
    const m = a.href.match(/scholar-([a-z0-9-]+)(?:$|[#&?])/);
    if (!m) return;
    const scholarId = m[1];
    if (!SCHOLAR_BIOS[scholarId]) return;
    a.addEventListener('click', e => {
      e.preventDefault();
      showScholarPopup(scholarId);
    });
  });
});
